12	export class InputField {
13	  constructor(
14	    protected readonly field: DMMF.SchemaArg,
15	    protected readonly context: GenerateContext,
16	    protected readonly source?: string,
17	  ) {}
18	  public toTS(): string {
19	    const property = buildInputField(this.field, this.context, this.source)
20	    return ts.stringify(property)
21	  }
22	}
