import { generatorHandler } from '@prisma/generator-helper'
import { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import * as ts from '@prisma/ts-builders'

generatorHandler({
  onManifest(config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'My Custom Generator',
      defaultOutput: './generated',
      version: '1.0.0',
      requiresEngines: [],
    }
  },

  async onGenerate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value || './generated'

    // Iterate over models in DMMF
    const fileMap: Record<string, string> = {}

    for (const model of options.dmmf.datamodel.models) {
      const iface = ts.interfaceDeclaration(model.name)

      for (const field of model.fields) {
        const fieldType = mapFieldType(field)
        const prop = ts.property(field.name, fieldType)

        if (!field.isRequired) {
          prop.optional()
        }

        iface.add(prop)
      }

      const file = ts.file()
      file.add(ts.exportFrom(iface))

      fileMap[`${model.name}.ts`] = ts.stringify(file)
    }

    // Write files
    for (const [fileName, content] of Object.entries(fileMap)) {
      const filePath = path.join(outputDir, fileName)
      await fs.mkdir(path.dirname(filePath), { recursive: true })
      await fs.writeFile(filePath, content)
    }
  },
})

function mapFieldType(field: DMMF.Field): ts.TypeBuilder {
  let baseType = field.type

  if (field.kind === 'scalar') {
    baseType = {'String': 'string', 'Int': 'number', 'Boolean': 'boolean'}[field.type] || field.type
  }

  let type = ts.namedType(baseType)
  if (field.isList) {
    type = ts.array(type)
  }

  return type
}
