---

## Implementation Plan: `@prisma/rest-client-generator`

### Overview

The package lives at `packages/rest-client-generator/`. It implements the `Generator` interface from `@prisma/generator`, uses `@prisma/ts-builders` to construct TypeScript AST fragments, writes three output files (`types.ts`, `client.ts`, `index.ts`) using Node's `fs/promises`, and registers itself in `@prisma/client-generator-registry`.

---

### Step 1 — Create the package scaffold

Create the following files. Every path below is relative to the repo root.

#### `packages/rest-client-generator/package.json`

```json
{
  "name": "@prisma/rest-client-generator",
  "version": "0.0.0",
  "description": "This package is intended for Prisma's internal use",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.js"
      },
      "import": {
        "types": "./dist/index.d.mts",
        "default": "./dist/index.mjs"
      }
    }
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/rest-client-generator"
  },
  "license": "Apache-2.0",
  "dependencies": {
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*",
    "@prisma/ts-builders": "workspace:*"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "prepublishOnly": "pnpm run build",
    "test": "vitest run --testTimeout 30000"
  },
  "files": [
    "dist"
  ],
  "sideEffects": false
}
```

Key points:
- `@prisma/internals` is **not** needed since we do not call `parseEnvValue` (we access `options.generator.output.value` directly).
- No `devDependencies` beyond what's hoisted at the workspace root.

#### `packages/rest-client-generator/tsconfig.json`

```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```

#### `packages/rest-client-generator/tsconfig.build.json`

```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist",
    "rootDir": "src"
  },
  "include": ["src"]
}
```

#### `packages/rest-client-generator/helpers/build.ts`

```typescript
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

---

### Step 2 — Create source files

#### `packages/rest-client-generator/src/type-mapping.ts`

This is a pure utility. It receives a `DMMF.Field` and returns the correct `TypeBuilder`.

```typescript
import type * as DMMF from '@prisma/dmmf'
import {
  array,
  bigintType,
  booleanType,
  namedType,
  numberType,
  stringType,
  TypeBuilder,
  unknownType,
} from '@prisma/ts-builders'

/**
 * Maps a Prisma scalar type name to the corresponding TypeScript TypeBuilder.
 * Relation fields (kind='object') are mapped to the related model interface name.
 * List fields are wrapped in array().
 */
export function mapPrismaTypeToTs(field: DMMF.Field): TypeBuilder {
  const base = getBaseType(field)
  if (field.isList) {
    return array(base)
  }
  return base
}

function getBaseType(field: DMMF.Field): TypeBuilder {
  if (field.kind === 'object') {
    // relation field — reference the related model interface
    return namedType(field.type)
  }
  if (field.kind === 'enum') {
    return namedType(field.type)
  }
  switch (field.type) {
    case 'String':
      return stringType
    case 'Int':
    case 'Float':
    case 'Decimal':
      return numberType
    case 'Boolean':
      return booleanType
    case 'DateTime':
      // JSON transport uses strings; using Date here for in-memory representation
      return namedType('Date')
    case 'BigInt':
      return bigintType
    case 'Json':
      return unknownType
    case 'Bytes':
      return namedType('Uint8Array')
    default:
      return unknownType
  }
}
```

#### `packages/rest-client-generator/src/generate-types.ts`

Builds the content of the output `types.ts` file.

```typescript
import type * as DMMF from '@prisma/dmmf'
import {
  array,
  docComment,
  ExportAllFrom,
  file,
  interfaceDeclaration,
  moduleExport,
  moduleExportFrom,
  namedType,
  property,
  stringify,
  stringLiteral,
  typeDeclaration,
  unionType,
} from '@prisma/ts-builders'

import { mapPrismaTypeToTs } from './type-mapping'

/**
 * Determines whether a field should be excluded from CreateInput.
 * Excludes: auto-generated IDs with defaults, read-only fields, relation back-references.
 */
function isAutoGenerated(field: DMMF.Field): boolean {
  if (field.isReadOnly) return true
  if (field.isId && field.hasDefaultValue) return true
  // relation fields that only reference inbound relations (no foreign key stored here)
  if (field.kind === 'object' && (!field.relationFromFields || field.relationFromFields.length === 0)) return true
  return false
}

/**
 * Determines whether a field should be excluded from UpdateInput.
 * Excludes: ID fields, read-only fields, relation back-references.
 */
function isImmutable(field: DMMF.Field): boolean {
  if (field.isId) return true
  if (field.isReadOnly) return true
  if (field.kind === 'object' && (!field.relationFromFields || field.relationFromFields.length === 0)) return true
  return false
}

export function generateTypesFileContent(models: readonly DMMF.Model[], enums: readonly DMMF.DatamodelEnum[]): string {
  const f = file()

  // --- Enum types ---
  for (const e of enums) {
    if (e.values.length === 0) continue
    const variants = e.values.map((v) => stringLiteral(v.name))
    const enumType = typeDeclaration(e.name, unionType(variants))
    if (e.documentation) {
      enumType.setDocComment(docComment(e.documentation))
    }
    f.add(moduleExport(enumType))
  }

  // --- Model interfaces and input types ---
  for (const model of models) {
    // Full model interface
    const iface = interfaceDeclaration(model.name)
    if (model.documentation) {
      // InterfaceDeclaration does not have setDocComment directly;
      // we wrap in Export and set doc comment there
    }
    for (const field of model.fields) {
      if (field.kind === 'unsupported') continue
      const tsType = mapPrismaTypeToTs(field)
      const prop = property(field.name, tsType)
      if (!field.isRequired) {
        prop.optional()
      }
      if (field.documentation) {
        prop.setDocComment(docComment(field.documentation))
      }
      iface.add(prop)
    }

    const ifaceExport = moduleExport(iface)
    if (model.documentation) {
      ifaceExport.setDocComment(docComment(model.documentation))
    }
    f.add(ifaceExport)

    // CreateInput type — omits auto-generated and read-only fields
    const createFields = model.fields.filter((f) => !isAutoGenerated(f) && f.kind !== 'unsupported')
    const createObj = interfaceDeclaration(`${model.name}CreateInput`)
    for (const field of createFields) {
      const tsType = mapPrismaTypeToTs(field)
      const prop = property(field.name, tsType)
      if (!field.isRequired || field.hasDefaultValue) {
        prop.optional()
      }
      createObj.add(prop)
    }
    f.add(moduleExport(createObj))

    // UpdateInput type — all non-ID, non-readonly fields, all optional
    const updateFields = model.fields.filter((f) => !isImmutable(f) && f.kind !== 'unsupported')
    const updateObj = interfaceDeclaration(`${model.name}UpdateInput`)
    for (const field of updateFields) {
      const tsType = mapPrismaTypeToTs(field)
      const prop = property(field.name, tsType).optional()
      updateObj.add(prop)
    }
    f.add(moduleExport(updateObj))

    // WhereUniqueInput — only ID fields
    const idFields = model.fields.filter((f) => f.isId)
    const whereUniqueObj = interfaceDeclaration(`${model.name}WhereUniqueInput`)
    for (const field of idFields) {
      whereUniqueObj.add(property(field.name, mapPrismaTypeToTs(field)))
    }
    f.add(moduleExport(whereUniqueObj))
  }

  return stringify(f, { newLine: 'trailing' })
}
```

**Important note on `moduleExport` vs `exportStatement`**: Looking at `Export.ts`, the factory function is named `moduleExport`, not `exportStatement`. The `File` class accepts `Export<any>` as a `FileItem`. This is what we use above.

**Important note on `stringLiteral`**: Imported from `@prisma/ts-builders`. It is exported from `StringLiteralType.ts` and re-exported via `index.ts`. `unionType` accepts an array of `TypeBuilder`; `StringLiteralType extends TypeBuilder`, so this is type-safe.

#### `packages/rest-client-generator/src/generate-client.ts`

Produces a plain TypeScript string (not using ts-builders for the function bodies, since ts-builders is a type-AST tool rather than a full expression AST). The function signatures use proper types; bodies use template literals for the fetch calls.

```typescript
import type * as DMMF from '@prisma/dmmf'

/** Lowercases first character */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Returns the name of the ID field for a model, or 'id' as a fallback.
 */
function getIdFieldName(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  return idField?.name ?? 'id'
}

function getIdFieldType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) return 'string'
  switch (idField.type) {
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    default:
      return 'string'
  }
}

export function generateClientFileContent(models: readonly DMMF.Model[], baseUrl: string): string {
  const modelClientBlocks: string[] = []

  for (const model of models) {
    const name = model.name
    const resourcePath = lcFirst(name)
    const idField = getIdFieldName(model)
    const idType = getIdFieldType(model)

    modelClientBlocks.push(`
export const ${lcFirst(name)}Client = {
  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`${baseUrl}/${resourcePath}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}[]>
  },

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const res = await fetch(\`${baseUrl}/${resourcePath}/\${where.${idField}}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${resourcePath}/\${where.${idField}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${resourcePath}/\${where.${idField}}\`, {
      method: 'DELETE',
    })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },
}`)
  }

  const typeImportNames = models
    .flatMap((m) => [
      m.name,
      `${m.name}CreateInput`,
      `${m.name}UpdateInput`,
      `${m.name}WhereUniqueInput`,
    ])
    .join(', ')

  return `import type { ${typeImportNames} } from './types'

${modelClientBlocks.join('\n')}
`
}
```

Note: `generate-client.ts` deliberately uses template literals for function bodies rather than ts-builders, because ts-builders covers type-level AST (interfaces, type aliases, imports, etc.) but has no facility for statement-level code generation (async function bodies, fetch calls, conditionals). The string-template approach for the implementation body is the correct pattern, exactly as the existing `Enum.ts` in `client-generator-js` uses template strings for `toJS()` and `toTS()` output.

#### `packages/rest-client-generator/src/generator.ts`

```typescript
import type * as DMMF from '@prisma/dmmf'
import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import fs from 'node:fs/promises'
import path from 'node:path'

import { generateClientFileContent } from './generate-client'
import { generateTypesFileContent } from './generate-types'

const DEFAULT_BASE_URL = 'http://localhost:3000'

export class RestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      defaultOutput: 'generated/rest-client',
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error(
        'rest-client-generator requires an output path. Add `output = "../generated/rest-client"` to your generator block.',
      )
    }

    const baseUrl = (options.generator.config['baseUrl'] as string | undefined) ?? DEFAULT_BASE_URL

    const models = options.dmmf.datamodel.models
    const enums = options.dmmf.datamodel.enums

    const typesContent = generateTypesFileContent(models, enums)
    const clientContent = generateClientFileContent(models, baseUrl)
    const indexContent = generateIndexFileContent()

    await fs.mkdir(outputDir, { recursive: true })
    await fs.writeFile(path.join(outputDir, 'types.ts'), typesContent, 'utf-8')
    await fs.writeFile(path.join(outputDir, 'client.ts'), clientContent, 'utf-8')
    await fs.writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8')
  }
}

function generateIndexFileContent(): string {
  return `export * from './types'
export * from './client'
`
}
```

Key points:
- `options.generator.output?.value` — this matches the `EnvValue` interface in `configuration.ts` where `value` is `null | string`. We guard against null/undefined with the optional chain.
- `options.generator.config['baseUrl']` — the config object has type `{ [key: string]: string | string[] | undefined }`, so the cast to `string | undefined` is safe.
- The `_config` parameter on `getManifest` is prefixed with `_` because TypeScript's `noImplicitAny` is off but `strict` is on; the underscore is the monorepo convention for unused parameters.

