---

### Step 2 — Source files

**`packages/rest-client-generator/src/index.ts`**
```typescript
export { RestClientGenerator } from './generator'
```

---

**`packages/rest-client-generator/src/type-mapping.ts`**

Maps DMMF field types to ts-builders `TypeBuilder` instances. Relation fields reference the related model name; list fields are wrapped in `array()`.

```typescript
import type * as DMMF from '@prisma/dmmf'
import {
  array,
  bigintType,
  booleanType,
  namedType,
  numberType,
  stringType,
  TypeBuilder,
  unknownType,
} from '@prisma/ts-builders'

/** Maps a DMMF field to its TypeScript TypeBuilder equivalent. */
export function mapPrismaTypeToTs(field: DMMF.Field): TypeBuilder {
  const base = getBaseType(field)
  return field.isList ? array(base) : base
}

function getBaseType(field: DMMF.Field): TypeBuilder {
  if (field.kind === 'object' || field.kind === 'enum') {
    return namedType(field.type)
  }
  switch (field.type) {
    case 'String':
      return stringType
    case 'Int':
    case 'Float':
    case 'Decimal':
      return numberType
    case 'Boolean':
      return booleanType
    case 'BigInt':
      return bigintType
    case 'DateTime':
      return namedType('Date')
    case 'Json':
      return unknownType
    case 'Bytes':
      return namedType('Uint8Array')
    default:
      return unknownType
  }
}
```

---

**`packages/rest-client-generator/src/generate-types.ts`**

Builds `types.ts` output using `@prisma/ts-builders`. Each enum becomes a string-literal union type. Each model gets four exported declarations: the full interface, `CreateInput` (omits auto-generated IDs and back-reference relations), `UpdateInput` (all scalar/enum fields optional, no IDs or readonly), and `WhereUniqueInput` (only ID fields).

```typescript
import type * as DMMF from '@prisma/dmmf'
import {
  docComment,
  interfaceDeclaration,
  moduleExport,
  property,
  stringLiteral,
  stringify,
  typeDeclaration,
  unionType,
} from '@prisma/ts-builders'

import { mapPrismaTypeToTs } from './type-mapping'

/** True when a field should be excluded from CreateInput. */
function isAutoGenerated(field: DMMF.Field): boolean {
  if (field.isReadOnly) return true
  // Auto-generated PK (e.g. cuid/uuid default)
  if (field.isId && field.hasDefaultValue) return true
  // Back-reference relations (no FK stored on this model)
  if (field.kind === 'object' && (!field.relationFromFields || field.relationFromFields.length === 0)) return true
  return false
}

/** True when a field must be excluded from UpdateInput. */
function isImmutable(field: DMMF.Field): boolean {
  if (field.isId) return true
  if (field.isReadOnly) return true
  if (field.kind === 'object' && (!field.relationFromFields || field.relationFromFields.length === 0)) return true
  return false
}

export function generateTypesFileContent(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const parts: string[] = []

  for (const e of enums) {
    if (e.values.length === 0) continue
    const decl = typeDeclaration(e.name, unionType(e.values.map((v) => stringLiteral(v.name))))
    const exported = moduleExport(decl)
    if (e.documentation) {
      exported.setDocComment(docComment(e.documentation))
    }
    parts.push(stringify(exported, { newLine: 'trailing' }))
  }

  for (const model of models) {
    // Full model interface
    const iface = interfaceDeclaration(model.name)
    for (const field of model.fields) {
      if (field.kind === 'unsupported') continue
      const prop = property(field.name, mapPrismaTypeToTs(field))
      if (!field.isRequired) prop.optional()
      if (field.documentation) prop.setDocComment(docComment(field.documentation))
      iface.add(prop)
    }
    const ifaceExport = moduleExport(iface)
    if (model.documentation) ifaceExport.setDocComment(docComment(model.documentation))
    parts.push(stringify(ifaceExport, { newLine: 'trailing' }))

    // CreateInput — omit auto-generated and back-reference fields
    const createIface = interfaceDeclaration(`${model.name}CreateInput`)
    for (const field of model.fields) {
      if (field.kind === 'unsupported' || isAutoGenerated(field)) continue
      const prop = property(field.name, mapPrismaTypeToTs(field))
      if (!field.isRequired || field.hasDefaultValue) prop.optional()
      createIface.add(prop)
    }
    parts.push(stringify(moduleExport(createIface), { newLine: 'trailing' }))

    // UpdateInput — mutable fields only, all optional
    const updateIface = interfaceDeclaration(`${model.name}UpdateInput`)
    for (const field of model.fields) {
      if (field.kind === 'unsupported' || isImmutable(field)) continue
      updateIface.add(property(field.name, mapPrismaTypeToTs(field)).optional())
    }
    parts.push(stringify(moduleExport(updateIface), { newLine: 'trailing' }))

    // WhereUniqueInput — ID fields only
    const whereIface = interfaceDeclaration(`${model.name}WhereUniqueInput`)
    for (const field of model.fields) {
      if (!field.isId) continue
      whereIface.add(property(field.name, mapPrismaTypeToTs(field)))
    }
    parts.push(stringify(moduleExport(whereIface), { newLine: 'trailing' }))
  }

  return parts.join('\n')
}
```

---

**`packages/rest-client-generator/src/generate-client.ts`**

Generates `client.ts` using template strings for async function bodies (ts-builders handles the type layer; statement-level code uses templates, matching the existing pattern in `client-generator-js`).

```typescript
import type * as DMMF from '@prisma/dmmf'

function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

function getIdField(model: DMMF.Model): { name: string; tsType: string } {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) return { name: 'id', tsType: 'string' }
  let tsType: string
  switch (idField.type) {
    case 'Int':
    case 'Float':
    case 'Decimal':
      tsType = 'number'
      break
    case 'BigInt':
      tsType = 'bigint'
      break
    default:
      tsType = 'string'
  }
  return { name: idField.name, tsType }
}

export function generateClientFileContent(models: readonly DMMF.Model[], baseUrl: string): string {
  const allTypeNames = models.flatMap((m) => [
    m.name,
    `${m.name}CreateInput`,
    `${m.name}UpdateInput`,
    `${m.name}WhereUniqueInput`,
  ])

  const importLine = `import type { ${allTypeNames.join(', ')} } from './types'`

  const clientBlocks = models.map((model) => {
    const name = model.name
    const varName = lcFirst(name)
    const path = lcFirst(name)
    const { name: idField } = getIdField(model)

    return `\
export const ${varName}Client = {
  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`${baseUrl}/${path}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}[]>
  },

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const res = await fetch(\`${baseUrl}/${path}/\${where.${idField}}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${path}/\${where.${idField}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const res = await fetch(\`${baseUrl}/${path}/\${where.${idField}}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  },
}`
  })

  return [importLine, '', ...clientBlocks].join('\n')
}
```

---

**`packages/rest-client-generator/src/generator.ts`**

```typescript
import type * as DMMF from '@prisma/dmmf'
import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import fs from 'node:fs/promises'
import path from 'node:path'

import { generateClientFileContent } from './generate-client'
import { generateTypesFileContent } from './generate-types'

const DEFAULT_BASE_URL = 'http://localhost:3000'

export class RestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      defaultOutput: 'generated/rest-client',
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error(
        'rest-client-generator requires an explicit output path. ' +
          'Add `output = "../generated/rest-client"` to the generator block.',
      )
    }

    const baseUrl = (options.generator.config['baseUrl'] as string | undefined) ?? DEFAULT_BASE_URL
    const models = options.dmmf.datamodel.models
    const enums = options.dmmf.datamodel.enums

    await fs.mkdir(outputDir, { recursive: true })
    await fs.writeFile(path.join(outputDir, 'types.ts'), generateTypesFileContent(models, enums), 'utf-8')
    await fs.writeFile(path.join(outputDir, 'client.ts'), generateClientFileContent(models, baseUrl), 'utf-8')
    await fs.writeFile(path.join(outputDir, 'index.ts'), `export * from './types'\nexport * from './client'\n`, 'utf-8')
  }
}
```

