**`packages/rest-client-generator/src/type-mapping.ts`**

Maps DMMF field types to ts-builders `TypeBuilder` instances. Relation fields reference the related model name; list fields are wrapped in `array()`.

```typescript
import type * as DMMF from '@prisma/dmmf'
import {
  array,
  bigintType,
  booleanType,
  namedType,
  numberType,
  stringType,
  TypeBuilder,
  unknownType,
} from '@prisma/ts-builders'

/** Maps a DMMF field to its TypeScript TypeBuilder equivalent. */
export function mapPrismaTypeToTs(field: DMMF.Field): TypeBuilder {
  const base = getBaseType(field)
  return field.isList ? array(base) : base
}

function getBaseType(field: DMMF.Field): TypeBuilder {
  if (field.kind === 'object' || field.kind === 'enum') {
    return namedType(field.type)
  }
  switch (field.type) {
    case 'String':
      return stringType
    case 'Int':
    case 'Float':
    case 'Decimal':
      return numberType
    case 'Boolean':
      return booleanType
    case 'BigInt':
      return bigintType
    case 'DateTime':
      return namedType('Date')
    case 'Json':
      return unknownType
    case 'Bytes':
      return namedType('Uint8Array')
    default:
      return unknownType
  }
}
```

