      if (!field.isRequired) prop.optional()
      if (field.documentation) prop.setDocComment(docComment(field.documentation))
      iface.add(prop)
    }
    const ifaceExport = moduleExport(iface)
    if (model.documentation) ifaceExport.setDocComment(docComment(model.documentation))
    parts.push(stringify(ifaceExport, { newLine: 'trailing' }))

    // CreateInput — omit auto-generated and back-reference fields
    const createIface = interfaceDeclaration(`${model.name}CreateInput`)
    for (const field of model.fields) {
      if (field.kind === 'unsupported' || isAutoGenerated(field)) continue
      const prop = property(field.name, mapPrismaTypeToTs(field))
      if (!field.isRequired || field.hasDefaultValue) prop.optional()
      createIface.add(prop)
    }
    parts.push(stringify(moduleExport(createIface), { newLine: 'trailing' }))

    // UpdateInput — mutable fields only, all optional
    const updateIface = interfaceDeclaration(`${model.name}UpdateInput`)
    for (const field of model.fields) {
      if (field.kind === 'unsupported' || isImmutable(field)) continue
      updateIface.add(property(field.name, mapPrismaTypeToTs(field)).optional())
    }
    parts.push(stringify(moduleExport(updateIface), { newLine: 'trailing' }))

    // WhereUniqueInput — ID fields only
    const whereIface = interfaceDeclaration(`${model.name}WhereUniqueInput`)
    for (const field of model.fields) {
      if (!field.isId) continue
      whereIface.add(property(field.name, mapPrismaTypeToTs(field)))
    }
    parts.push(stringify(moduleExport(whereIface), { newLine: 'trailing' }))
  }

  return parts.join('\n')
}
```

