function isAutoGenerated(field: Field): boolean {
  return (field.isId && field.hasDefaultValue) || field.isUpdatedAt === true
}

/**
 * Wraps the given type builder in `Array<...>` if the field is a list.
 */
function wrapList(type: TypeBuilder, field: Field): TypeBuilder {
  if (!field.isList) return type
  return namedType('Array').addGenericArgument(type)
}

/**
 * Generates TypeScript source for a single model's types and the enum union types
 * used by that model. Returns a string of TypeScript declarations.
 */
export function generateModelTypes(model: Model, enumNames: Set<string>): string {
  const lines: string[] = []

  // Main model interface: all fields at their natural optionality
  const mainInterface = interfaceDeclaration(model.name)
  for (const field of model.fields) {
    if (field.kind === 'object') continue // skip relation fields in the plain interface
    const tsType = wrapList(dmmfTypeToTsType(field.type), field)
    const prop = property(field.name, tsType)
    if (!field.isRequired) prop.optional()
    mainInterface.add(prop)
  }
  lines.push(stringify(mainInterface, { newLine: 'trailing' }))

  // CreateInput: exclude auto-generated fields; relations are excluded (object kind)
  const createInterface = interfaceDeclaration(`${model.name}CreateInput`)
  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (isAutoGenerated(field)) continue
    const tsType = wrapList(dmmfTypeToTsType(field.type), field)
    const prop = property(field.name, tsType)
    if (!field.isRequired || field.hasDefaultValue) prop.optional()
    createInterface.add(prop)
  }
  lines.push(stringify(createInterface, { newLine: 'trailing' }))

  // UpdateInput: mutable non-id scalar fields, all optional
  const updateInterface = interfaceDeclaration(`${model.name}UpdateInput`)
  for (const field of model.fields) {
    if (field.kind === 'object') continue
    if (field.isId || field.isReadOnly) continue
    const tsType = wrapList(dmmfTypeToTsType(field.type), field)
    updateInterface.add(property(field.name, tsType).optional())
  }
  lines.push(stringify(updateInterface, { newLine: 'trailing' }))

  // WhereUniqueInput: only the ID fields
  const whereInterface = interfaceDeclaration(`${model.name}WhereUniqueInput`)
  for (const field of model.fields) {
    if (!field.isId) continue
    const tsType = dmmfTypeToTsType(field.type)
    whereInterface.add(property(field.name, tsType))
  }
  lines.push(stringify(whereInterface, { newLine: 'trailing' }))

  return lines.join('\n')
}

/**
 * Generates a string-literal union type declaration for a Prisma enum.
 * Example: `type Role = "ADMIN" | "USER"`
 */
export function generateEnumType(dmmfEnum: DatamodelEnum): string {
  const literals = dmmfEnum.values.map((v) => stringLiteral(v.name))
  if (literals.length === 0) return ''
  const union = unionType(literals)
  const decl = typeDeclaration(dmmfEnum.name, union)
  return stringify(decl, { newLine: 'trailing' })
}

/**
 * Produces the full content of `types.ts` for the generated REST client,
 * containing enum union types and per-model TypeScript interfaces.
 */
export function generateTypesFile(models: readonly Model[], enums: readonly DatamodelEnum[]): string {
  const enumNames = new Set(enums.map((e) => e.name))
  const parts: string[] = []

  for (const dmmfEnum of enums) {
    const enumType = generateEnumType(dmmfEnum)
    if (enumType) parts.push(enumType)
  }

  for (const model of models) {
    parts.push(generateModelTypes(model, enumNames))
  }

  return parts.join('\n')
}

