import type { Model } from '@prisma/dmmf'

/**
 * Lowercases the first character of the given string, used to derive the client
 * variable name from the model name (e.g. `Post` → `postClient`).
 */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generates the typed client object for a single model with CRUD methods that
 * call a REST API via `fetch`. The `baseUrl` parameter is included verbatim so
 * callers can supply a runtime value or a literal string.
 *
 * Because ts-builders targets TypeScript declarations, not imperative code, the
 * client methods are emitted as a template-string block.
 */
function generateModelClient(model: Model, baseUrl: string): string {
  const varName = `${lcFirst(model.name)}Client`
  const endpoint = `${baseUrl}/${lcFirst(model.name)}`

  return `\
export const ${varName} = {
  async findMany(params?: { skip?: number; take?: number }): Promise<${model.name}[]> {
    const query = params ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
    const res = await fetch(\`${endpoint}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${model.name} failed: \${res.statusText}\`)
    return res.json() as Promise<${model.name}[]>
  },

  async findUnique(where: ${model.name}WhereUniqueInput): Promise<${model.name} | null> {
    const id = Object.values(where)[0]
    const res = await fetch(\`${endpoint}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${model.name} failed: \${res.statusText}\`)
    return res.json() as Promise<${model.name}>
  },

  async create(data: ${model.name}CreateInput): Promise<${model.name}> {
    const res = await fetch(\`${endpoint}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${model.name} failed: \${res.statusText}\`)
    return res.json() as Promise<${model.name}>
  },

  async update(where: ${model.name}WhereUniqueInput, data: ${model.name}UpdateInput): Promise<${model.name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`${endpoint}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${model.name} failed: \${res.statusText}\`)
    return res.json() as Promise<${model.name}>
  },

  async delete(where: ${model.name}WhereUniqueInput): Promise<${model.name}> {
    const id = Object.values(where)[0]
    const res = await fetch(\`${endpoint}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${model.name} failed: \${res.statusText}\`)
    return res.json() as Promise<${model.name}>
  },
}
`
}

/**
 * Produces the full content of `client.ts` for the generated REST client,
 * importing all model types from `./types` and exporting a typed client object
 * per model.
 */
export function generateClientFile(models: readonly Model[], baseUrl: string): string {
  if (models.length === 0) return ''

  const typeImports = models.flatMap((m) => [
    m.name,
    `${m.name}CreateInput`,
    `${m.name}UpdateInput`,
    `${m.name}WhereUniqueInput`,
  ])

  const importLine = `import type { ${typeImports.join(', ')} } from './types'\n\n`
  const clients = models.map((m) => generateModelClient(m, baseUrl)).join('\n')

  return importLine + clients
}

