import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateClientFile } from './generate-client'
import { generateTypesFile } from './generate-types'

const DEFAULT_BASE_URL = 'http://localhost:3000'

const missingOutputErrorMessage = `An output path is required for the \`prisma-rest-client\` generator. Please provide one in your schema:

generator restClient {
  provider = "prisma-rest-client"
  output   = "../src/generated/rest-client"
}
`

function getOutputPath(config: GeneratorConfig): string {
  if (!config.output?.value) {
    throw new Error(missingOutputErrorMessage)
  }
  return config.output.value
}

export class RestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = getOutputPath(options.generator)
    const baseUrl = options.generator.config.baseUrl ?? DEFAULT_BASE_URL

    const models = options.dmmf.datamodel.models
    const enums = options.dmmf.datamodel.enums

    await mkdir(outputDir, { recursive: true })

    const typesContent = generateTypesFile(models, enums)
    const clientContent = generateClientFile(models, baseUrl)

    const indexContent = `export * from './types'\nexport * from './client'\n`

    await Promise.all([
      writeFile(path.join(outputDir, 'types.ts'), typesContent, 'utf-8'),
      writeFile(path.join(outputDir, 'client.ts'), clientContent, 'utf-8'),
      writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8'),
    ])
  }
}

