import { mkdtemp, readFile, rm } from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { describe, expect, it, afterEach } from 'vitest'

import { RestClientGenerator } from './generator'

/** Minimal DMMF document fixture with a Post model and a Role enum */
function makeOptions(outputDir: string, overrides: Partial<GeneratorOptions> = {}): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-rest-client' },
      output: { fromEnvVar: null, value: outputDir },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '',
      isCustomOutput: true,
    },
    otherGenerators: [],
    schemaPath: '',
    datamodel: '',
    version: '',
    datasources: [],
    dmmf: {
      datamodel: {
        enums: [
          {
            name: 'Role',
            values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
          },
        ],
        models: [
          {
            name: 'Post',
            dbName: null,
            schema: null,
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
                type: 'Int',
              },
              {
                kind: 'scalar',
                name: 'title',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                hasDefaultValue: false,
                type: 'String',
              },
              {
                kind: 'scalar',
                name: 'published',
                isRequired: false,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                hasDefaultValue: true,
                default: false,
                type: 'Boolean',
              },
              {
                kind: 'enum',
                name: 'role',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: false,
                isReadOnly: false,
                hasDefaultValue: false,
                type: 'Role',
              },
            ],
          },
        ],
        types: [],
        indexes: [],
      },
      schema: { inputObjectTypes: {}, outputObjectTypes: {}, enumTypes: {} },
      mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
    },
    ...overrides,
  } as unknown as GeneratorOptions
}

describe('RestClientGenerator', () => {
  const generator = new RestClientGenerator()
  let tmpDir: string | undefined

  afterEach(async () => {
    if (tmpDir) {
      await rm(tmpDir, { recursive: true, force: true })
      tmpDir = undefined
    }
  })

  it('has the correct generator name', () => {
    expect(generator.name).toBe('prisma-rest-client')
  })

  it('getManifest returns pretty name and no required engines', async () => {
    const manifest = await generator.getManifest({} as never)
    expect(manifest.prettyName).toBe('Prisma REST Client')
    expect(manifest.requiresEngines).toEqual([])
  })

  it('throws when output is missing', async () => {
    const options = makeOptions('')
    options.generator.output = null
    await expect(generator.generate(options)).rejects.toThrow('output path is required')
  })

  it('generates types.ts, client.ts, and index.ts', async () => {
    tmpDir = await mkdtemp(path.join(os.tmpdir(), 'rest-client-gen-'))
    await generator.generate(makeOptions(tmpDir))

    const [types, client, index] = await Promise.all([
      readFile(path.join(tmpDir, 'types.ts'), 'utf-8'),
      readFile(path.join(tmpDir, 'client.ts'), 'utf-8'),
      readFile(path.join(tmpDir, 'index.ts'), 'utf-8'),
    ])

    // Enum union type
    expect(types).toContain('type Role =')
    expect(types).toContain('"ADMIN"')
    expect(types).toContain('"USER"')

    // Model interface
    expect(types).toContain('interface Post {')
    expect(types).toContain('id: number')
    expect(types).toContain('title: string')
    expect(types).toContain('published?: boolean')
    expect(types).toContain('role: Role')

    // CreateInput omits auto-generated id
    expect(types).toContain('interface PostCreateInput {')
    expect(types).not.toMatch(/interface PostCreateInput \{[^}]*\bid:/)

    // UpdateInput has optional fields
    expect(types).toContain('interface PostUpdateInput {')
    expect(types).toContain('title?: string')

    // WhereUniqueInput has only the id
    expect(types).toContain('interface PostWhereUniqueInput {')
    expect(types).toContain('id: number')

    // Client file imports types and exports client
    expect(client).toContain("from './types'")
    expect(client).toContain('export const postClient =')
    expect(client).toContain('findMany')
    expect(client).toContain('findUnique')
    expect(client).toContain('create')
    expect(client).toContain('update')
    expect(client).toContain('delete')

    // Index re-exports
    expect(index).toContain("from './types'")
    expect(index).toContain("from './client'")
  })

  it('uses a custom baseUrl when provided', async () => {
    tmpDir = await mkdtemp(path.join(os.tmpdir(), 'rest-client-gen-'))
    const options = makeOptions(tmpDir)
    options.generator.config = { baseUrl: 'https://api.example.com/v1' }
    await generator.generate(options)

    const client = await readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(client).toContain('https://api.example.com/v1/post')
  })
})

